-- ================================================================
-- AAM OFFICIAL MEMBER IMPORT - CORRECTED
--
-- Root cause fix: members.id is a FK to auth.users — you cannot
-- insert a random uuid_generate_v4() directly into public.members.
--
-- HOW THIS WORKS:
--   Step 1 creates auth.users accounts (password: 123456).
--   The on_auth_user_created trigger auto-creates public.members rows.
--   Step 2 updates those rows with official AAM IDs and categories.
--
-- Safe to re-run (ON CONFLICT DO NOTHING / upsert on email).
-- Run in Supabase SQL Editor (executes as postgres superuser).
-- ================================================================

-- ================================================================
-- STEP 1: CREATE AUTH ACCOUNTS
-- ================================================================

INSERT INTO auth.users (
  id, instance_id, aud, role,
  email, encrypted_password,
  email_confirmed_at,
  raw_app_meta_data, raw_user_meta_data,
  created_at, updated_at,
  confirmation_token, recovery_token
)
SELECT 
  v.id::uuid, v.instance_id::uuid, v.aud::text, v.role::text,
  v.email::text, v.encrypted_password::text,
  v.email_confirmed_at::timestamptz,
  v.raw_app_meta_data::jsonb, v.raw_user_meta_data::jsonb,
  v.created_at::timestamptz, v.updated_at::timestamptz,
  v.confirmation_token::text, v.recovery_token::text
